#include <bits/stdc++.h>
using namespace std;
long long e[1000001],f[100000];
int main(){
	long long n;
	cin>>n;
	long long i=0,b=0,a=0,c=0,k=0;
	for(i=2;i<=1000000;i++){
		if(e[i]==0){
			f[k]=i;
			k++;
			for(int j=2;i*j<=1000000;j++){
				e[i*j]=1;
			}
		}
	}
	i=0;
	while(i<k){
		if(n%f[i]==0){
			if(b){
				cout<<" * ";
			}
			c=0;
			while(n%f[i]==0){
				c++;
				n=n/f[i];
			}
			cout<<f[i];
			if(c>1){
				cout<<"^"<<c;
			}
			b=1;
		}
		i++;
	}
	if(n>1){
		if(b){
			cout<<" * ";
		}
		cout<<n;
	}
	return 0;
}
